void push(int x) {
    stack[++top] = x;
}

int pop() {
    return stack[top--];
}

int peek() {
    return stack[top];
}

int isEmpty() {
    return top == -1;
}

void sortedInsert(int element) {
    if (isEmpty() || peek() < element) {
        push(element);
        return;
    }
    int temp = pop();
    sortedInsert(element);
    push(temp);
}

void sortStack() {
    if (isEmpty())
        return;
    int temp = pop();
    sortStack();
    sortedInsert(temp);
}

